INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('torque_scenario_no_contextual_controls', 'torque_on_loop_uniform_field scenario cannot do Rule-31c per-state contextual controls — the slider panel is all-or-nothing (no row-wrapper ids, no applyVisibleControls call), shown only at the explore state; guided states expose no state-relevant slider', 'MAJOR', 'peter_parker:renderer_primitives', 'FIXED + VERIFIED 2026-07-05. Was: the #torque_sliders panel was four bare label+input pairs with NO row-wrapper ids and NO applyVisibleControls call (only STATE_11 showed the panel — the old last-state-only pattern). TWO-PART FIX landed: (a) renderer_primitives wrapped the four sliders in tq_n_row/tq_i_row/tq_b_row/tq_theta_row (built once) + calls applyVisibleControls({N:tq_n_row,I:tq_i_row,B:tq_b_row,theta:tq_theta_row}, stateDef.visible_controls) in the torqueSlidersEl branch (scenario-gated), reusing the shared helper; (b) json_author added per-state visible_controls arrays (S5=[N,I], S6=[B], S7=[theta], S11=[N,I,B,theta], watch beats none) + show_sliders:true and fixed STATE_11''s show_sliders array bug. Eye-walker pixel-verified run 20260705-045637: each state shows exactly its relevant slider row set, explore shows all.', 'A field_3d scenario used by a Rule-31 concept must support per-state contextual controls (row-wrapper ids + applyVisibleControls reading stateDef.visible_controls) BEFORE the concept is authored/retrofitted to Rule 31 — a Socratic->straightforward narration retrofit alone does not make a concept Rule-31-compliant if its scenario is control-incapable.', 'manual', 'For torque_on_current_loop_in_field, confirm each guided state exposes only its relevant slider row(s) and the explore state exposes all. If the panel is all-or-nothing (only the explore state shows any slider), Rule-31c is unmet.', 'FIXED', ARRAY['torque_on_current_loop_in_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/data/concepts/torque_on_current_loop_in_field.json'], 'session_2026-07-05_torque_socratic_retrofit_rule31_gaps', 'incident'),
('torque_static_early_states', 'torque_on_current_loop_in_field STATE_1/2/3 are rotation_mode "static" (zero motion) — violates Rule 31b "no static state; every state alive with distinct motion"', 'MODERATE', 'ambiguous', 'FIXED + VERIFIED 2026-07-05. Was: STATE_1/2/3/5/7/10 authored rotation_mode:"static" (frozen picture, Rule 31b violation). FIX: renderer_primitives added distinct sustained motion per state (json_author selects the mode) — S1 current_flow_idle (loop-edge breathing pulse), S2 arrow_grow (F1 continuous opacity pulse), S3 arrow_grow+cancel_pulse (both F arrows in-phase throb), S5 mu_reveal (mu opacity pulse), S7 tau_max_throb (bounded tau pulse), S10 swap_loop (loop<->bar-magnet cross-fade). NOTE the design journey (3 verification rounds): one-time size-grow reveals were tried first but were invisible on screen due to FORESHORTENING (F/mu point near the camera axis, so a 3D length change barely moves the 2D projection) AND were a Rule-29 concern (growing a fixed-magnitude vector). Final design = continuous bounded OPACITY pulses (period 3.0s, non-aliasing with THE EYE''s 1s sampling; Rule-29-clean = brightness not size, honest full length). Eye-walker pixel-verified oscillation on all of S1/S2/S3/S5 (run 20260705-045637: e.g. S2 F1 pixel-count trough 5 -> peak 150). rotation_mode metadata no longer literally "static" on any guided state.', 'Every guided state (including setup / watch-this beats) must show distinct auto-playing motion (Rule 31b) — a rotation_mode "static" state is a design smell to resolve at author time, not ship.', 'manual', 'For each guided state, THE EYE motion profile (D-checks) must show sustained above-floor adjacent-frame motion; a state that is flat for its whole duration is a static-state violation. NOTE: D6/D7 can PASS on marching-dot baseline while the INTENDED distinct motion is absent — verify the taught element (arrow/vector/loop) with a pixel-proxy oscillation measure, not just the gate.', 'FIXED', ARRAY['torque_on_current_loop_in_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/data/concepts/torque_on_current_loop_in_field.json'], 'session_2026-07-05_torque_socratic_retrofit_rule31_gaps', 'incident')
